// Verifiser hemmelig header fra Supabase Edge Function
const inputData = $input.first();
const headers = inputData.json.headers;
const body = inputData.json.body;

// Hent secret fra n8n env (sett under Settings > Variables)
const correctSecret = $env.N8N_HEADER_AUTH_VALUE || $env.VIRANODE_SECRET;
const receivedSecret = headers['x-videomill-auth'] || headers['x-viranode-secret'];

if (!correctSecret || receivedSecret !== correctSecret) {
  return [{ json: { authorized: false, error: 'Feil hemmelig kode' } }];
}

return [{ json: { ...body, authorized: true } }];

parameters.jsonBody:
={
  "model": "llama-3.1-8b-instant",
  "messages": [
    {
      "role": "system",
      "content": "You are a viral short-form video script writer. Always respond with valid JSON only — no markdown, no code blocks, no placeholders. The JSON must have: title, description, hashtags (array), scenes (array of objects with: narration, visual_description, duration_seconds, search_keywords array)."
    },
    {
      "role": "user",
      "content": {{ JSON.stringify('Create a viral video script about: ' + $('Webhook - Video Request').first().json.body.topic + '. User instructions: ' + ($('Webhook - Video Request').first().json.body.promp || 'Make it engaging and short') + '. Platform: ' + ($('Webhook - Video Request').first().json.body.platform || 'tiktok') + '. Language: ' + ($('Webhook - Video Request').first().json.body.language || 'nb') + '. Target audience: ' + ($('Webhook - Video Request').first().json.body.target_audience || 'general') + '. Create 3-5 scenes, each 5-8 seconds. Use real content, no placeholders.') }}
    }
  ],
  "max_tokens": 2000,
  "temperature": 0.7
}

parameters.jsCode:
const response = $input.first().json.choices[0].message.content;
try {
  // Prøv å parse JSON direkte
  let script;
  try {
    script = JSON.parse(response);
  } catch {
    // Prøv å hente JSON fra markdown code blocks
    const jsonMatch = response.match(/```(?:json)?\n?([\s\S]*?)\n?```/) || response.match(/(\{[\s\S]*\})/);
    if (!jsonMatch) throw new Error('No JSON found in response');
    script = JSON.parse(jsonMatch[1] || jsonMatch[0]);
  }

  const webhookData = $('Webhook - Video Request').first().json.body;
  return [{ json: {
    ...script,
    video_id:        webhookData.video_id,
    user_id:         webhookData.user_id,
    voice_id:        webhookData.voice_id || 'nb-NO-PernilleNeural',
    platform:        webhookData.platform || 'tiktok',
    language:        webhookData.language || 'nb',
    aspect_ratio:    webhookData.aspect_ratio || '9:16',
    target_audience: webhookData.target_audience || 'general',
  }}];
} catch(e) {
  throw new Error('Failed to parse script JSON: ' + e.message + '\nResponse was: ' + response.substring(0, 200));
}

// Mapper voice_id fra frontend til edge-tts format
// edge-tts krever 'Neural'-suffix på norske stemmer
const item = items[0].json;
const voiceId = item.voice_id || 'nb-NO-PernilleNeural';

// Legg til 'Neural' hvis mangler
const tts_voice = voiceId.endsWith('Neural') ? voiceId : voiceId + 'Neural';

// Norske stemmer: nb-NO-PernilleNeural, nb-NO-FinnNeural, nb-NO-IselinNeural
// Engelske: en-US-AriaNeural, en-US-AndrewNeural, en-GB-SoniaNeural

return [{ json: { ...item, tts_voice } }];

const { execSync } = require('child_process');
const item = items[0].json;
const videoId = item.video_id;
const voice   = item.tts_voice || 'nb-NO-PernilleNeural';

// Bygg fullstendig tekst fra scener
let rawText = '';
if (item.scenes && Array.isArray(item.scenes) && item.scenes.length > 0) {
  rawText = item.scenes.map(s => s.narration || '').filter(Boolean).join('. ');
} else {
  rawText = item.topic || item.title || 'VideoMill produksjon';
}

// Rens tekst for shell-farlige tegn
const cleanText = rawText
  .replace(/["'`$\\]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 2000); // Max 2000 tegn

const dir        = `/workspace/video_assets/${videoId}`;
const outputPath = `${dir}/voiceover.mp3`;

try {
  execSync(`mkdir -p ${dir}`, { shell: '/bin/bash' });
  execSync(`edge-tts --voice "${voice}" --text "${cleanText}" --write-media "${outputPath}"`, {
    encoding: 'utf-8',
    timeout: 300000,
    shell: '/bin/bash',
  });

  return [{ json: { ...item, voiceover_path: outputPath, engine_status: 'success', voice_used: voice } }];
} catch (err) {
  throw new Error(`Voiceover feilet (ID: ${videoId}, stemme: ${voice}): ${err.message}`);
}

const item = items[0].json;
const scenes  = item.scenes || [];
const videoId = item.video_id || $('Webhook - Video Request').first().json.body.video_id;

return scenes.map((scene, index) => ({
  json: {
    ...item,
    video_id:         videoId,
    scene,
    batchIndex:       index,
    duration_seconds: scene.duration_seconds || 5,
    search_query:     (scene.search_keywords && scene.search_keywords[0]) || item.topic || 'nature',
  }
}));

const videos = $input.first().json.videos || [];
if (!videos.length) return [{ json: { clip_url: null } }];
const best = videos[0];
// Velg HD eller beste tilgjengelige
const hdFile = best.video_files.find(f => f.quality === 'hd') ||
               best.video_files.find(f => f.quality === 'sd') ||
               best.video_files[0];
return [{ json: { clip_url: hdFile.link, clip_id: best.id } }];

const { execSync } = require('child_process');
const item       = items[0].json;
const videoId    = item.video_id || $('Webhook - Video Request').first().json.body.video_id;
const clipUrl    = item.clip_url;
const batchIndex = item.batchIndex || 0;
const duration   = item.duration_seconds || 5;
const dir        = `/workspace/video_assets/${videoId}`;

execSync(`mkdir -p ${dir}/clips`, { shell: '/bin/bash' });

if (!clipUrl) {
  // Generer svart klipp som fallback
  const cmd = `ffmpeg -y -f lavfi -i color=c=black:size=1080x1920:rate=30 -t ${duration} -c:v libx264 -preset fast ${dir}/clips/scene_${batchIndex}.mp4`;
  execSync(cmd, { encoding: 'utf-8', timeout: 120000, shell: '/bin/bash' });
  return [{ json: { ...item, video_id: videoId, clip_path: `${dir}/clips/scene_${batchIndex}.mp4`, success: true } }];
}

const cmd = `ffmpeg -y -i "${clipUrl}" -t ${duration} -c:v libx264 -preset fast -an "${dir}/clips/scene_${batchIndex}.mp4"`;
try {
  execSync(cmd, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
  return [{ json: { ...item, video_id: videoId, clip_path: `${dir}/clips/scene_${batchIndex}.mp4`, success: true } }];
} catch(err) { throw new Error('FFmpeg download failed: ' + err.message); }

const { execSync } = require('child_process');
const item    = items[0].json;
const videoId = item.video_id || $('Webhook - Video Request').first().json.body.video_id;
const dir     = `/workspace/video_assets/${videoId}`;

execSync(`mkdir -p ${dir}/clips`, { shell: '/bin/bash' });

const files = execSync(`ls ${dir}/clips/scene_*.mp4 2>/dev/null || echo ''`, {
  encoding: 'utf-8', shell: '/bin/bash'
}).trim();

if (!files) throw new Error(`Ingen scene-filer funnet i ${dir}/clips/`);

const cmd = `cd ${dir}/clips && ls scene_*.mp4 | sort -V | sed "s/^/file '/;s/$/'/" > filelist.txt && ffmpeg -y -f concat -safe 0 -i filelist.txt -c:v libx264 -preset fast "${dir}/concat.mp4"`;
try {
  execSync(cmd, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
  return [{ json: { ...item, video_id: videoId, concat_path: `${dir}/concat.mp4`, success: true } }];
} catch(err) { throw new Error('FFmpeg concat failed: ' + err.message); }

const { execSync } = require('child_process');
const item    = items[0].json;
const videoId = item.video_id || $('Webhook - Video Request').first().json.body.video_id;
const dir     = `/workspace/video_assets/${videoId}`;

try {
  execSync(`mkdir -p ${dir}`, { shell: '/bin/bash' });

  // Kombiner lyd og video
  execSync(`ffmpeg -y -i "${dir}/concat.mp4" -i "${dir}/voiceover.mp3" -c:v copy -c:a aac -shortest "${dir}/final_16x9.mp4"`, {
    encoding: 'utf-8', timeout: 300000, shell: '/bin/bash'
  });

  return [{ json: { ...item, video_id: videoId, master_path: `${dir}/final_16x9.mp4` } }];
} catch(err) {
  throw new Error('Voiceover/Merge failed: ' + err.message);
}

const { execSync } = require('child_process');
const item    = items[0].json;
const videoId = item.video_id || $('Webhook - Video Request').first().json.body.video_id;
const dir     = `/workspace/video_assets/${videoId}`;
const ratio   = item.aspect_ratio || '9:16';

try {
  if (ratio === '9:16' || ratio !== '16:9') {
    // TikTok/Reels 9:16
    execSync(`ffmpeg -y -i "${dir}/final_16x9.mp4" -vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2,setsar=1" "${dir}/final_9x16.mp4"`, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });
  }
  // Instagram 1:1
  execSync(`ffmpeg -y -i "${dir}/final_16x9.mp4" -vf "scale=1080:1080:force_original_aspect_ratio=decrease,pad=1080:1080:(ow-iw)/2:(oh-ih)/2,setsar=1" "${dir}/final_1x1.mp4"`, { encoding: 'utf-8', timeout: 300000, shell: '/bin/bash' });

  return [{ json: { ...item, video_id: videoId, success: true } }];
} catch(err) {
  throw new Error('FFmpeg scale failed: ' + err.message);
}

const { execSync } = require('child_process');
const item       = items[0].json;
const videoId    = item.video_id;
const userId     = item.user_id;
const dir        = `/workspace/video_assets/${videoId}`;
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey  = $env.SUPABASE_SERVICE_ROLE_KEY;

const uploads = [
  { file: 'final_16x9.mp4', format: '16x9' },
  { file: 'final_9x16.mp4', format: '9x16' },
  { file: 'final_1x1.mp4',  format: '1x1'  },
];

const uploadedUrls = {};

for (const u of uploads) {
  const filePath    = `${dir}/${u.file}`;
  const storagePath = `${userId}/${videoId}/${u.file}`;
  try {
    execSync(`curl -sf -X POST "${supabaseUrl}/storage/v1/object/videos/${storagePath}" \
      -H "Authorization: Bearer ${serviceKey}" \
      -H "Content-Type: video/mp4" \
      --data-binary @"${filePath}"`,
      { encoding: 'utf-8', timeout: 600000, shell: '/bin/bash' }
    );
    uploadedUrls[`video_url_${u.format.replace(':','x')}`] = `${supabaseUrl}/storage/v1/object/public/videos/${storagePath}`;
    console.log(`Uploaded ${u.format} for video ${videoId}`);
  } catch(err) {
    console.log(`Upload ${u.format} failed (non-fatal): ${err.message}`);
  }
}

return [{ json: { ...item, video_id: videoId, user_id: userId, ...uploadedUrls } }];

const { execSync } = require('child_process');
const videoId = items[0].json.video_id || $('Webhook - Video Request').first().json.body.video_id;
try {
  execSync(`rm -rf /workspace/video_assets/${videoId}`, { encoding: 'utf-8', timeout: 30000, shell: '/bin/bash' });
  return [{ json: { ...items[0].json, cleanup: 'done' } }];
} catch (err) {
  console.log('Cleanup (non-fatal):', err.message);
  return [{ json: { ...items[0].json, cleanup: 'failed' } }];
}

// Parser Ollama-respons og mapper felt til DB-skjema
const resp = $input.first().json.response || $input.first().json.message?.content || '';

let topics = [];
try {
  // Prøv direkte parse
  topics = JSON.parse(resp);
} catch {
  try {
    // Prøv å hente JSON-array fra tekst
    const match = resp.match(/\[[\s\S]*\]/);
    if (match) topics = JSON.parse(match[0]);
  } catch(e) {
    throw new Error('Klarte ikke parse trender fra Ollama: ' + e.message + '\nRespens: ' + resp.substring(0, 300));
  }
}

if (!Array.isArray(topics) || topics.length === 0) {
  throw new Error('Ollama returnerte ingen trender');
}

// Kart fra kategori til standard plattform (fallback)
const platformByCategory = {
  tech: 'youtube',  motivation: 'tiktok', history: 'youtube',
  science: 'youtube', crime: 'tiktok', finance: 'youtube',
  health: 'instagram', mystery: 'tiktok',
};

return topics.map(t => ({ json: {
  title:           t.title           || t.name        || 'Ukjent topic',
  category:        t.category        || 'general',
  viral_score:     t.rank            || t.viral_score  || Math.floor(Math.random() * 40 + 55),
  heat_level:      t.heat            || t.heat_level   || 'rising',
  growth_stat:     t.reason          || t.growth_stat  || null,
  tags:            Array.isArray(t.tags) ? t.tags : [],
  platform:        t.platform        || platformByCategory[t.category] || 'youtube',
  target_audience: t.target_audience || (t.category ? t.category + ' enthusiasts' : 'General audience'),
} }));
